const parseNode = $('Parse dz callback').item.json;
const trackId = parseNode.track_id;
const chatId = parseNode.chat_id;

return [{
  json: {
    track_id: trackId,
    chat_id: chatId,
    deezer_track_url: `https://api.deezer.com/track/${trackId}`,
    songlink_url: `https://api.song.link/v1-alpha.1/links?url=https://www.deezer.com/track/${trackId}&userCountry=US&songIfSingle=true`
  }
}];

const body = $json.body;
const callback = body.callback_query;
const message = callback.message;
const chatId = message.chat.id;
const messageId = message.message_id;
const from = callback.from;
const username = from.username || null;
const firstName = from.first_name || '';
const lastName = from.last_name || '';
const isPremium = from.is_premium || false;
const languageCode = from.language_code || 'en';
const callbackData = callback.data || '';

// ✅ business_connection_id из message
const businessConnectionId = message.business_connection_id || null;

const parts = callbackData.split('|');
const trackId = parts[1];

return [{
  json: {
    chat_id: chatId,
    message_id: messageId,
    username: username,
    first_name: firstName,
    last_name: lastName,
    is_premium: isPremium,
    language_code: languageCode,
    track_id: trackId,
    callback_data: callbackData,
    business_connection_id: businessConnectionId
  }
}];

const songlink = $('HTTP Request').first().json;
const deezer = $('HTTP Request Deezer').first().json;
const trackId = deezer.id;
const trackName = deezer.title;
const artistName = deezer.artist.name;

const platforms = songlink.linksByPlatform || {};

// Check direct links
const youtubeUrl = platforms.youtube?.url;
const soundcloudUrl = platforms.soundcloud?.url;

let streamUrl = youtubeUrl || soundcloudUrl;
let source = youtubeUrl ? 'YouTube' : (soundcloudUrl ? 'SoundCloud' : null);

// If no direct links then use YouTube via yt-dlp
if (!streamUrl) {
  const searchQuery = `${artistName} - ${trackName} official audio`;
  streamUrl = `ytsearch:${searchQuery}`;
  source = 'YouTube (via yt-dlp search)';
  console.log(`No direct YouTube/SoundCloud URL for track ${trackId}. Using YouTube search: "${searchQuery}"`);
}

return [{
  json: {
    stream_url: streamUrl,
    track_id: String(trackId),
    output_path: `/tmp/ps_${trackId}.mp3`,
    source: source,
    track_name: trackName,
    artist_name: artistName
  }
}];

const items = $input.all();
const deezer = $('HTTP Request Deezer').first().json;
const songlink = $('HTTP Request').first().json;

const youtubeEntity = Object.values(songlink.entitiesByUniqueId || {})
  .find(e => e.apiProvider === 'youtube');

const correctArtistName = youtubeEntity?.artistName 
  || Object.values(songlink.entitiesByUniqueId || {})
      .find(e => e.apiProvider !== 'deezer')?.artistName
  || deezer.artist.name; 

const correctTitle = youtubeEntity?.title || deezer.title;

for (const item of items) {
  if (item.binary?.data) {
    item.binary.audio = item.binary.data;
    delete item.binary.data;
    item.binary.audio.fileName = `${correctArtistName} - ${correctTitle}.mp3`;
    item.binary.audio.mimeType = 'audio/mpeg';
  }
}
return items;

const items = $input.all();
const deezer = $('HTTP Request Deezer').first().json;
const songlink = $('HTTP Request').first().json;
const chatId = $('Parse dz callback').first().json.chat_id;  

const youtubeEntity = Object.values(songlink.entitiesByUniqueId || {})
  .find(e => e.apiProvider === 'youtube');

const correctArtistName = youtubeEntity?.artistName 
  || Object.values(songlink.entitiesByUniqueId || {})
      .find(e => e.apiProvider !== 'deezer')?.artistName
  || deezer.artist.name;

const correctTitle = youtubeEntity?.title || deezer.title;

for (const item of items) {
  if (item.binary?.data) {
    item.binary.thumbnail = item.binary.data;
    delete item.binary.data;
    item.binary.thumbnail.fileName = 'cover.jpg';
    item.binary.thumbnail.mimeType = 'image/jpeg';
  }

  item.json = {
    chat_id: String(chatId),
    title: correctTitle,
    performer: correctArtistName,
    duration: String(deezer.duration)
  };
}
return items;

